cramers_rule <- function(A, b) {
  det_A <- det(A)
  if (abs(det_A) < 1e-10) stop("Singular matrix")

  n <- length(b)
  x <- numeric(n)

  for (i in 1:n) {
    A_i <- A
    A_i[, i] <- b  # Replace column i
    x[i] <- det(A_i) / det_A
  }
  return(x)
}

A <- matrix(c(2, 1, 3, 5), nrow = 2, byrow = TRUE)
b <- c(8, 19)
cramers_rule(A, b)  # 3, 2

